            if text[i] == '{': depth += 1
            elif text[i] == '}':
                depth -= 1
                if depth == 0:
                    end = i + 1
                    break
        body = re.sub(r'\s+', ' ', text[start:end]).strip()
        h = hashlib.sha1(body.encode()).hexdigest()[:10]
        groups.setdefault(h, []).append(str(file))
    if groups:
        print(f'\n{fn}')
        for h, files in groups.items():
            print(f'  {h}: {len(files)} files')
            for f in files:
                print(f'    {f}')
